const raw = $input.item.json;
// multipart/form-data: fields land directly on json OR nested under body
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const file = $input.item.binary?.file || $input.item.binary?.data;

const importId  = body.import_batch_id || body.import_id || body.quote_id || `IMP_${Date.now()}`;
const jobId     = body.job_id     || `job_${Date.now()}`;
const source    = body.source     || 'import';

const successUrl = body.callbackSuccessUrl || body.callbacks?.success_url || null;
const failedUrl  = body.callbackFailedUrl  || body.callbacks?.failed_url  || null;

if (!successUrl) {
  // Log all available keys for debugging
  throw new Error("Missing callbackSuccessUrl. Received keys: " + Object.keys(body).join(', '));
}

let mimeType = body.mime_type || 'unknown';
if (file && file.mimeType) {
  mimeType = file.mimeType;
}

return {
  json: {
    importId,
    jobId,
    filename: file?.fileName || body.source_file || 'document.pdf',
    mime_type: mimeType,
    callbackSuccessUrl: successUrl,
    callbackFailedUrl:  failedUrl,
    source,
    source_format: 'pdf'
  },
  binary: $input.item.binary
};

const meta = $("Metadata & Validation2").first().json;
let extractedRows = [];

try {
  let rawText = $("OpenAI: Parse2").first().json.choices[0].message.content;
  if (rawText.includes("```json")) {
     rawText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();
  }
  extractedRows = JSON.parse(rawText);
} catch(e) {
  extractedRows = [];
}

return {
  json: {
    import_batch_id: meta.importId,
    job_id: meta.jobId,
    status: "parsed",
    rows: extractedRows,
    callbackSuccessUrl: meta.callbackSuccessUrl
  }
};

return {
  json: {
    import_batch_id: $input.item.json.importId,
    job_id: $input.item.json.jobId,
    status: "failed",
    error: "Неподдерживаемый формат: " + $input.item.json.mime_type + ". Загрузите PDF-файл.",
    callbackFailedUrl: $input.item.json.callbackFailedUrl
  }
};
